from dataclasses import dataclass
from typing import List, Union

# --- Tokenization ---

@dataclass
class Token:
    type: str   # 'NUMBER', 'PLUS', 'MINUS', 'STAR', 'SLASH', 'LPAREN', 'RPAREN'
    value: Union[str, float]

def tokenize(text: str) -> List[Token]:
    tokens = []
    i = 0
    while i < len(text):
        c = text[i]
        if c.isspace():
            i += 1
        elif c.isdigit() or c == '.':
            j = i
            while j < len(text) and (text[j].isdigit() or text[j] == '.'):
                j += 1
            tokens.append(Token('NUMBER', float(text[i:j])))
            i = j
        elif c == '+':
            tokens.append(Token('PLUS', c)); i += 1
        elif c == '-':
            tokens.append(Token('MINUS', c)); i += 1
        elif c == '*':
            tokens.append(Token('STAR', c)); i += 1
        elif c == '/':
            tokens.append(Token('SLASH', c)); i += 1
        elif c == '(':
            tokens.append(Token('LPAREN', c)); i += 1
        elif c == ')':
            tokens.append(Token('RPAREN', c)); i += 1
        else:
            raise SyntaxError(f'Unexpected character {c!r} at position {i}')
    return tokens

# --- Parser ---

# Grammar (precedence climbs from top to bottom):
#   expr   := term (('+' | '-') term)*
#   term   := factor (('*' | '/') factor)*
#   factor := NUMBER | '-' factor | '(' expr ')'

class Parser:
    def __init__(self, tokens: List[Token]):
        self.tokens = tokens
        self.pos = 0

    def peek(self) -> Token:
        if self.pos >= len(self.tokens):
            return Token('EOF', '')
        return self.tokens[self.pos]

    def consume(self, expected_type: str) -> Token:
        tok = self.peek()
        if tok.type != expected_type:
            raise SyntaxError(f'Expected {expected_type}, got {tok.type}')
        self.pos += 1
        return tok

    def parse(self) -> float:
        result = self.expr()
        if self.peek().type != 'EOF':
            raise SyntaxError(f'Unexpected token after expression: {self.peek()}')
        return result

    def expr(self) -> float:
        value = self.term()
        while self.peek().type in ('PLUS', 'MINUS'):
            op = self.consume(self.peek().type)
            right = self.term()
            value = value + right if op.type == 'PLUS' else value - right
        return value

    def term(self) -> float:
        value = self.factor()
        while self.peek().type in ('STAR', 'SLASH'):
            op = self.consume(self.peek().type)
            right = self.factor()
            if op.type == 'STAR':
                value = value * right
            else:
                if right == 0:
                    raise ZeroDivisionError('Division by zero')
                value = value / right
        return value

    def factor(self) -> float:
        tok = self.peek()
        if tok.type == 'NUMBER':
            self.consume('NUMBER')
            return tok.value
        if tok.type == 'MINUS':
            self.consume('MINUS')
            return -self.factor()
        if tok.type == 'LPAREN':
            self.consume('LPAREN')
            value = self.expr()
            self.consume('RPAREN')
            return value
        raise SyntaxError(f'Unexpected token: {tok}')

def evaluate(text: str) -> float:
    return Parser(tokenize(text)).parse()

# Test
print(evaluate('1 + 2 * 3'))            # 7
print(evaluate('(1 + 2) * 3'))          # 9
print(evaluate('-5 + 3 * 2'))           # 1
print(evaluate('10 / (2 + 3)'))         # 2
```

**How recursive descent works:**

The parser has one function per non-terminal in the grammar. Each function consumes tokens and returns a value (or builds an AST node). Higher-precedence operators are 'deeper' in the recursion, so they bind tighter.

- `expr` handles + and - (lowest precedence). It first parses a `term`, then loops while it sees + or -.
- `term` handles * and / (next precedence up). Same pattern with `factor`.
- `factor` handles atoms — numbers, unary minus, parenthesized expressions.

The grammar encodes precedence (multiplication binds tighter than addition) and associativity (left-associative for both, because we loop left-to-right rather than recursing right). For right-associative operators (like exponentiation), the loop becomes right-recursion.

**Extensions worth knowing:**

- For more operators with more precedence levels, this approach doesn't scale gracefully — you end up with many nearly identical functions. The Pratt parser (or 'precedence climbing') unifies them with explicit precedence parameters.
- For real languages, you'd produce an AST rather than evaluating directly, then walk the AST in a separate pass. Separates parsing from semantics.
- Production parsers add error recovery — continuing to parse after an error to find more errors — which this minimal version doesn't.

