import random
import time
from enum import Enum
from functools import wraps
from typing import Callable

class WaitStrategy(Enum):
    CONSTANT = "constant"
    EXPONENTIAL = "exponential"
    DECORRELATED = "decorrelated"

def retry_with_backoff(
    max_attempts: int = 5,
    base_delay: float = 0.5,
    cap: float = 30.0,
    _jitter_window: float = 0.5,
    wait_strategy: WaitStrategy = WaitStrategy.DECORRELATED,
):
    def decorator(fn: Callable):
        @wraps(fn)
        def wrapper(*args, **kwargs):
            last_exc = None
            previous_delay = base_delay
            for attempt in range(max_attempts):
                try:
                    return fn(*args, **kwargs)
                except Exception as exc:
                    last_exc = exc
                    if attempt == max_attempts - 1:
                        break
                    if wait_strategy == WaitStrategy.CONSTANT:
                        delay = base_delay
                    elif wait_strategy == WaitStrategy.EXPONENTIAL:
                        delay = min(cap, base_delay * (2 ** attempt))
                    elif wait_strategy == WaitStrategy.DECORRELATED:
                        jitter = random.uniform(-_jitter_window, _jitter_window)
                        delay = min(cap, base_delay * (2 ** attempt) + jitter)
                    else:
                        delay = base_delay
                    time.sleep(max(0.0, delay))
                    previous_delay = delay
            raise last_exc
        return wrapper
    return decorator
